 {"id":"rust_proxy-kyn","title":"Add HTTP server for /metrics endpoint","description":"## Scope

Implement a lightweight HTTP server that exposes the Prometheus metrics endpoint.

## Implementation

```rust
// In new file: src/metrics_server.rs

use axum::{routing::get, Router};
use std::net::SocketAddr;
use tokio::sync::watch;

async fn metrics_handler() -> String {
    crate::metrics::encode_metrics()
}

async fn health_handler() -> &'static str {
    "OK"
}

pub async fn run_metrics_server(
    bind: SocketAddr,
    path: String,
    mut shutdown: watch::Receiver<bool>,
) {
    let app = Router::new()
        .route(&path, get(metrics_handler))
        .route("/health", get(health_handler));  // Optional health endpoint

    tracing::info\!(
        bind = %bind,
        path = %path,
        "Starting metrics server"
    );

    let listener = tokio::net::TcpListener::bind(bind).await.unwrap();

    axum::serve(listener, app)
        .with_graceful_shutdown(async move {
            let _ = shutdown.changed().await;
            tracing::info\!("Metrics server shutting down");
        })
        .await
        .unwrap();
}
```

## Integration with Daemon

```rust
// In run_daemon() in main.rs
if config.settings.metrics_enabled {
    let metrics_bind = format\!(
        "{}:{}",
        config.settings.metrics_bind.as_deref().unwrap_or("0.0.0.0"),
        config.settings.metrics_port
    ).parse()?;

    let metrics_path = config.settings.metrics_path.clone()
        .unwrap_or_else(|| "/metrics".to_string());

    let shutdown_rx = shutdown_tx.subscribe();
    tokio::spawn(run_metrics_server(metrics_bind, metrics_path, shutdown_rx));
}
```

