Create a new `metrics.rs` module that defines all Prometheus metric types for rust_proxy.

## Metrics Structure

```rust
use prometheus::{
    Counter, CounterVec, Gauge, GaugeVec, Histogram, HistogramVec,
    Opts, Registry, histogram_opts,
};
use lazy_static::lazy_static;

lazy_static! {
    pub static ref REGISTRY: Registry = Registry::new();

    // Counters
    pub static ref REQUESTS_TOTAL: CounterVec = CounterVec::new(
        Opts::new("rust_proxy_requests_total", "Total proxy requests"),
        &["proxy", "status"]
    ).unwrap();

    pub static ref BYTES_SENT: CounterVec = CounterVec::new(
        Opts::new("rust_proxy_bytes_sent_total", "Total bytes sent"),
        &["proxy"]
    ).unwrap();

    pub static ref BYTES_RECEIVED: CounterVec = CounterVec::new(
        Opts::new("rust_proxy_bytes_received_total", "Total bytes received"),
        &["proxy"]
    ).unwrap();

    pub static ref HEALTH_CHECKS: CounterVec = CounterVec::new(
        Opts::new("rust_proxy_health_checks_total", "Health check results"),
        &["proxy", "result"]
    ).unwrap();

    pub static ref FAILOVERS: CounterVec = CounterVec::new(
        Opts::new("rust_proxy_failovers_total", "Failover events"),
        &["from", "to"]
    ).unwrap();

    // Gauges
    pub static ref ACTIVE_CONNECTIONS: GaugeVec = GaugeVec::new(
        Opts::new("rust_proxy_active_connections", "Current active connections"),
        &["proxy"]
    ).unwrap();

    pub static ref PROXY_HEALTH: GaugeVec = GaugeVec::new(
        Opts::new("rust_proxy_proxy_health", "Proxy health status (1=healthy, 0=unhealthy)"),
        &["proxy"]
    ).unwrap();

    // Histograms
    pub static ref CONNECTION_DURATION: HistogramVec = HistogramVec::new(
        histogram_opts!(
            "rust_proxy_connection_duration_seconds",
            "Connection duration in seconds",
            vec![0.001, 0.005, 0.01, 0.05, 0.1, 0.5, 1.0, 5.0, 10.0, 30.0, 60.0]
        ),
        &["proxy"]
    ).unwrap();

    pub static ref HEALTH_CHECK_LATENCY: HistogramVec = HistogramVec::new(
        histogram_opts!(
            "rust_proxy_health_check_latency_seconds",
            "Health check latency in seconds",
            vec![0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1.0, 2.5, 5.0]
        ),
        &["proxy"]
    ).unwrap();
}

/// Initialize and register all metrics with the registry
pub fn init_metrics() -> Result<(), prometheus::Error> {
    REGISTRY.register(Box::new(REQUESTS_TOTAL.clone()))?;
    REGISTRY.register(Box::new(BYTES_SENT.clone()))?;
    REGISTRY.register(Box::new(BYTES_RECEIVED.clone()))?;
    REGISTRY.register(Box::new(HEALTH_CHECKS.clone()))?;
    REGISTRY.register(Box::new(FAILOVERS.clone()))?;
    REGISTRY.register(Box::new(ACTIVE_CONNECTIONS.clone()))?;
    REGISTRY.register(Box::new(PROXY_HEALTH.clone()))?;
    REGISTRY.register(Box::new(CONNECTION_DURATION.clone()))?;
    REGISTRY.register(Box::new(HEALTH_CHECK_LATENCY.clone()))?;
    Ok(())
}

/// Encode all metrics to Prometheus text format
pub fn encode_metrics() -> String {
    use prometheus::Encoder;
    let encoder = prometheus::TextEncoder::new();
    let mut buffer = Vec::new();
    encoder.encode(&REGISTRY.gather(), &mut buffer).unwrap();
    String::from_utf8(buffer).unwrap()
}
```

## Design Decisions

- **lazy_static**: Standard pattern for global metrics in Rust
- **Custom Registry**: Allows us to control exactly what gets exported
- **Label choices**: Designed for useful aggregation (by proxy, by status, etc.)
- **Histogram buckets**: Tuned for expected latency ranges

## Acceptance Criteria

- New `src/metrics.rs` file created
- All metric types defined
- `init_metrics()` function to register all metrics
- `encode_metrics()` function to output Prometheus format
