use notify::{Config, RecommendedWatcher, RecursiveMode, Watcher, Event};
use std::path::Path;
use std::sync::mpsc;
use std::time::Duration;

pub struct ConfigWatcher {
    watcher: RecommendedWatcher,
    rx: mpsc::Receiver<Result<Event, notify::Error>>,
}

impl ConfigWatcher {
    pub fn new(config_path: &Path) -> Result<Self> {
        let (tx, rx) = mpsc::channel();

        let mut watcher = RecommendedWatcher::new(
            move |res| { let _ = tx.send(res); },
            Config::default()
                .with_poll_interval(Duration::from_secs(2))
        )?;

        watcher.watch(config_path, RecursiveMode::NonRecursive)?;

        Ok(Self { watcher, rx })
    }

    pub fn poll(&self) -> Option<()> {
        // Returns Some(()) if config file changed
        // Handles debouncing internally
    }
}
```

### Key Design Decisions

1. **Debouncing**: Config file saves often trigger multiple events (write, chmod, etc.). Debounce to avoid multiple reloads.
2. **Poll interval**: 2 seconds is reasonable - not too aggressive, but responsive enough.
3. **Error handling**: Watcher failures should log but not crash daemon.

