+        Ok(ips) => {
+            let mut list: Vec<String> = ips.into_iter().collect();
+            list.sort();
+            push_trace_step(
+                &mut steps,
+                "DNS resolution",
+                TraceStatus::Ok,
+                Some(dns_duration),
+                Some(format!(
+                    "Resolved {} IP(s): {}",
+                    list.len(),
+                    if list.is_empty() {
+                        "none".to_string()
+                    } else {
+                        list.join(", ")
+                    }
+                )),
+            );
+            (list, None)
+        }
+        Err(err) => {
+            let msg = err.to_string();
+            push_trace_step(
+                &mut steps,
+                "DNS resolution",
+                TraceStatus::Failed,
+                Some(dns_duration),
+                Some(msg.clone()),
+            );
+            (Vec::new(), Some(msg))
+        }
+    };
+
+    // Step 2: Proxy selection
+    let selection_start = Instant::now();
+    let state = StateStore::load().await?;
+    let load_balancer = LoadBalancer::new();
+    let selected_proxy = load_balancer
+        .select_proxy(
+            config.settings.load_balance_strategy,
+            &config.proxies,
+            &state,
+        )
+        .await;
+    let selection_duration = selection_start.elapsed();
+
+    let proxy_id = match selected_proxy {
+        Some(id) => {
+            push_trace_step(
+                &mut steps,
+                "Proxy selection",
+                TraceStatus::Ok,
+                Some(selection_duration),
+                Some(format!(
+                    "Selected {id} (strategy: {:?})",
+                    config.settings.load_balance_strategy
+                )),
+            );
+            id
+        }
+        None => {
+            push_trace_step(
+                &mut steps,
+                "Proxy selection",
+                TraceStatus::Failed,
+                Some(selection_duration),
+                Some("No healthy proxy available".to_string()),
+            );
+            push_trace_skip(
+                &mut steps,
+                "Proxy connect",
+                "Skipped due to proxy selection failure",
+            );
+            push_trace_skip(
+                &mut steps,
+                "CONNECT request",
+                "Skipped due to proxy selection failure",
+            );
+            push_trace_skip(
+                &mut steps,
+                "Proxy response",
+                "Skipped due to proxy selection failure",
+            );
+            push_trace_skip(
+                &mut steps,
+                "TLS handshake",
+                "Skipped due to proxy selection failure",
