+            push_trace_skip(
+                &mut steps,
+                "CONNECT request",
+                "Skipped due to proxy selection failure",
+            );
+            push_trace_skip(
+                &mut steps,
+                "Proxy response",
+                "Skipped due to proxy selection failure",
+            );
+            push_trace_skip(
+                &mut steps,
+                "TLS handshake",
+                "Skipped due to proxy selection failure",
+            );
+
+            let report = TraceReport {
+                input: target.input.clone(),
+                target: TraceTargetInfo {
+                    host: target.host.clone(),
+                    port: target.port,
+                    scheme: target.scheme.clone(),
+                },
+                resolved_ips,
+                dns_error,
