+            }
+            Ok(Err(err)) => {
+                push_trace_step(
+                    &mut steps,
+                    "TLS handshake",
+                    TraceStatus::Failed,
+                    Some(tls_duration),
+                    Some(err.to_string()),
+                );
+            }
+            Err(_) => {
+                push_trace_step(
+                    &mut steps,
+                    "TLS handshake",
+                    TraceStatus::Failed,
+                    Some(tls_duration),
+                    Some("TLS handshake timed out".to_string()),
+                );
+            }
+        }
+    }
+
+    let report = TraceReport {
+        input: target.input.clone(),
+        target: TraceTargetInfo {
+            host: target.host.clone(),
+            port: target.port,
+            scheme: target.scheme.clone(),
+        },
+        resolved_ips,
+        dns_error,
